+func TestEnvOr(t *testing.T) {
+	t.Setenv("X_TEST", "")
+	if got := envOr("X_TEST", "fallback"); got != "fallback" {
+		t.Fatalf("unexpected: %q", got)
+	}
+	t.Setenv("X_TEST", "value")
+	if got := envOr("X_TEST", "fallback"); got != "value" {
